/// <summary>
/// Extension of the <c>CustInvoiceJour</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(CustInvoiceJour))]
final class CustInvoiceJourETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initFromSalesTable</c> method to populate the fields
/// specific to the ETGSPAIN model.
/// </summary>
/// <param name="salesTable">SalesTable record</param>
/// <param name="_salesParmTable">SalesParmTable record</param>
public void initFromSalesTable(SalesTable salesTable, SalesParmTable _salesParmTable)
{
    next initFromSalesTable(salesTable, _salesParmTable);

    // Contrato
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (salesTable.MatchingAgreement)
        {
            AgreementHeader             agreementHeader;

            agreementHeader = AgreementHeader::find(salesTable.MatchingAgreement);

            this.ETGSPAINAgreementId = agreementHeader.ETGSPAINgetAgreementId();

            // Cupo
            if (agreementHeader.ETGSPAINPurchHasAgreementQuotas)
            {
                // Solo mes y año: Ejemplo: Julio 2022
                this.ETGSPAINMonthQuota = strFmt("%1 %2", mthName(mthOfYr(salesTable.ETGSPAINPurchExecutionFromDate)), year(salesTable.ETGSPAINPurchExecutionFromDate));
            }
            else
            {
                this.ETGSPAINMonthQuota = strFmt("%1 %2", mthName(mthOfYr(this.ETGSPAINPurchExecutionFromDate)), year(this.ETGSPAINPurchExecutionFromDate));
            }
        }

        // Fechas de ejecución
        this.ETGSPAINPurchExecutionFromDate  = salesTable.ETGSPAINPurchExecutionFromDate;
        this.ETGSPAINPurchExecutionDueDate   = salesTable.ETGSPAINPurchExecutionDueDate;
    }
}
